const express = require('express');
const app = express();

app.use(express.json());

const levels = [
  { level: 1, reward: { coins: 100, gems: 5 } },
  { level: 2, reward: { coins: 200, gems: 10 } },
  // ...
];

app.post('/levels/:levelId/complete', (req, res) => {
  const levelId = parseInt(req.params.levelId);
  const { score, time } = req.body;

  const level = levels.find(l => l.level === levelId);

  if (!level) {
    return res.status(404).json({ error: 'Level not found' });
  }

  if (score < level.minScore || time > level.maxTime) {
    return res.status(400).json({ error: 'Invalid score or time' });
  }

  res.json({ reward: level.reward });
});

